SELECT COUNT(*) AS resolved_complaints_count
FROM resolutions
WHERE resolving_agency_id = 1;

SELECT type_name
FROM complaint_types
WHERE category = 'residential' AND severity_level = 'major';

SELECT complaint_id, MAX(update_date) AS latest_update
FROM complaint_updates
GROUP BY complaint_id;

SELECT DISTINCT agency_name
FROM complaints
ORDER BY agency_name;

SELECT complaint_id
FROM complaints
ORDER BY created_date DESC;
